const BASE = import.meta.env.VITE_API_BASE || '/api';

export class ApiError extends Error {
  constructor(message, status) {
    super(message);
    this.name = 'ApiError';
    this.status = status;
  }
}

export function isNetworkError(e) {
  return e instanceof TypeError || (e && (e.name === 'TimeoutError' || e.name === 'AbortError'));
}

async function request(path, { method = 'GET', token, body } = {}) {
  const res = await fetch(BASE + path, {
    method,
    headers: {
      'Content-Type': 'application/json',
      ...(token ? { Authorization: '[REDACTED] ' + token } : {}),
    },
    body: body !== undefined ? JSON.stringify(body) : undefined,
    signal: AbortSignal.timeout(8000),
  });
  let data = null;
  try {
    data = await res.json();
  } catch (e) {
    data = null;
  }
  if (!res.ok) {
    throw new ApiError((data && data.error) || 'Request failed', res.status);
  }
  return data;
}

export function login({ email, password }) {
  return request('/auth/login', { method: 'POST', body: { username: email, password } });
}

export function register({ email, password, role }) {
  return request('/auth/register', {
    method: 'POST',
    body: { username: email, password, role: role === 'investor' ? 'investor' : 'founder' },
  });
}

export function getProfile(token, id) {
  return request('/profiles/' + id, { token });
}

export function saveProfile(token, profileId, payload) {
  if (profileId) {
    return request('/profiles/' + profileId, { method: 'PATCH', token, body: payload });
  }
  return request('/profiles', { method: 'POST', token, body: payload });
}

export function toProfilePayload(form) {
  return {
    company_name: form.name,
    country: form.country || null,
    stage: form.stage,
    num_of_employees: form.numEmployees === '' ? null : Number(form.numEmployees),
    industry: form.sectors.join(','),
    target_region: form.targetRegion || null,
    arr: form.arr === '' ? null : Number(form.arr),
    where_you_operate: form.geography,
    website: form.website.split(',').map((s) => s.trim()).filter(Boolean),
    description_product: form.need,
  };
}

export function extractProfile(userId) {
  return request('/extract/profile', { method: 'POST', body: { userId } });
}

export function getMatches({ userId, role }) {
  const path = role === 'investor'
    ? '/matches/investors/' + userId + '/founders'
    : '/matches/founders/' + userId + '/investors';
  return request(path + '?limit=50');
}

const INVESTOR_TYPES = {
  vc: 'Venture Capital',
  angel: 'Angel Investor',
  cvc: 'Corporate VC',
  pe: 'Private Equity',
  'family-office': 'Family Office',
};

const cap = (s) => (s ? s.charAt(0).toUpperCase() + s.slice(1) : s);

export function matchToCandidate(m, role) {
  const a = m.attributes || {};
  const reasons = m.reasons || [];
  const base = {
    userId: m.userId,
    score: Math.round(m.score * 100),
    vectorScore: Math.round(m.vectorScore * 100),
    attributeScore: Math.round(m.attributeScore * 100),
    reasons,
    rationale: reasons.length
      ? cap(reasons.join(' · '))
      : 'Ranked by semantic similarity between both profiles.',
  };
  if (role === 'investor') {
    return {
      ...base,
      name: a.company_name || 'Unnamed startup',
      type: 'Startup' + (a.stage ? ' · ' + cap(a.stage) : ''),
      dot: '#3f8f6b',
      sectors: (a.industry || []).map(cap),
    };
  }
  return {
    ...base,
    name: a.firm_name || 'Unnamed investor',
    type: INVESTOR_TYPES[a.investor_type] || 'Investor',
    dot: '#b08636',
    sectors: (a.sectors || []).map(cap),
  };
}

export function fromProfile(p) {
  return {
    name: p.company_name || '',
    website: (p.website || []).join(', '),
    stage: p.stage || '',
    geography: p.where_you_operate || '',
    country: p.country || '',
    targetRegion: p.target_region || '',
    numEmployees: p.num_of_employees == null ? '' : String(p.num_of_employees),
    arr: p.arr == null ? '' : String(p.arr),
    sectors: p.industry ? p.industry.split(',') : [],
    need: p.description_product || '',
    consent: false,
  };
}

const { Router } = require('express');
const profileService = require('../services/profile.service');
const authenticate = require('../middleware/authenticate');

const router = Router();

router.use(authenticate);

/**
 * @openapi
 * /profiles:
 *   post:
 *     summary: Create a profile and link it to the current user
 *     tags: [Profiles]
 *     requestBody:
 *       required: true
 *       content:
 *         application/json:
 *           schema:
 *             allOf:
 *               - $ref: '#/components/schemas/ProfileInput'
 *               - type: object
 *                 required: [company_name]
 *     responses:
 *       201:
 *         description: Profile created and linked to the current user
 *         content:
 *           application/json:
 *             schema:
 *               $ref: '#/components/schemas/Profile'
 *       400:
 *         description: Missing or invalid fields
 *         content:
 *           application/json:
 *             schema:
 *               $ref: '#/components/schemas/Error'
 *       404:
 *         description: User not found
 *         content:
 *           application/json:
 *             schema:
 *               $ref: '#/components/schemas/Error'
 *       409:
 *         description: User already has a profile
 *         content:
 *           application/json:
 *             schema:
 *               $ref: '#/components/schemas/Error'
 */
router.post('/', async (req, res, next) => {
  try {
    const { company_name: companyName } = req.body;
    if (!companyName) {
      return res.status(400).json({ error: 'company_name is required' });
    }

    const profile = await profileService.createProfile(req.user.sub, req.body);
    res.status(201).json(profile);
  } catch (err) {
    next(err);
  }
});

/**
 * @openapi
 * /profiles/{id}:
 *   get:
 *     summary: Get a profile by id
 *     tags: [Profiles]
 *     parameters:
 *       - in: path
 *         name: id
 *         required: true
 *         schema:
 *           type: string
 *           format: uuid
 *     responses:
 *       200:
 *         description: Profile found
 *         content:
 *           application/json:
 *             schema:
 *               $ref: '#/components/schemas/Profile'
 *       404:
 *         description: Profile not found
 *         content:
 *           application/json:
 *             schema:
 *               $ref: '#/components/schemas/Error'
 */
router.get('/:id', async (req, res, next) => {
  try {
    const profile = await profileService.getProfile(req.params.id);
    res.json(profile);
  } catch (err) {
    next(err);
  }
});

/**
 * @openapi
 * /profiles/{id}:
 *   patch:
 *     summary: Update the current user's profile
 *     tags: [Profiles]
 *     parameters:
 *       - in: path
 *         name: id
 *         required: true
 *         schema:
 *           type: string
 *           format: uuid
 *     requestBody:
 *       required: true
 *       content:
 *         application/json:
 *           schema:
 *             $ref: '#/components/schemas/ProfileInput'
 *     responses:
 *       200:
 *         description: Profile updated
 *         content:
 *           application/json:
 *             schema:
 *               $ref: '#/components/schemas/Profile'
 *       403:
 *         description: Profile does not belong to the current user
 *         content:
 *           application/json:
 *             schema:
 *               $ref: '#/components/schemas/Error'
 *       404:
 *         description: Profile not found
 *         content:
 *           application/json:
 *             schema:
 *               $ref: '#/components/schemas/Error'
 */
router.patch('/:id', async (req, res, next) => {
  try {
    const profile = await profileService.updateProfile(req.user.sub, req.params.id, req.body);
    res.json(profile);
  } catch (err) {
    next(err);
  }
});

module.exports = router;

